const { ethers } = require('ethers');
require('dotenv').config();

const RPC_URL = process.env.RPC_URL || '';
const PRIVATE_KEY = process.env.PRIVATE_KEY || '';
const CHAIN_ID = process.env.CHAIN_ID ? Number(process.env.CHAIN_ID) : undefined;

if (!RPC_URL) throw new Error('Missing RPC_URL');
if (!PRIVATE_KEY) throw new Error('Missing PRIVATE_KEY');

const provider = new ethers.JsonRpcProvider(RPC_URL, CHAIN_ID);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

async function getBalance(address = wallet.address) {
  return await provider.getBalance(address);
}

async function sendEth(to, amountEth, txOptions = {}) {
  if (!ethers.isAddress(to)) throw new Error('Invalid recipient address');
  const value = ethers.parseEther(String(amountEth));
  const tx = await wallet.sendTransaction({
    to,
    value,
    gasLimit: txOptions.gasLimit,
    maxFeePerGas: txOptions.maxFeePerGas,
    maxPriorityFeePerGas: txOptions.maxPriorityFeePerGas,
    nonce: txOptions.nonce,
    chainId: txOptions.chainId ?? CHAIN_ID
  });
  return await tx.wait();
}

function getContract(address, abi) {
  if (!ethers.isAddress(address)) throw new Error('Invalid contract address');
  return new ethers.Contract(address, abi, wallet);
}

async function readContract(address, abi, method, args = []) {
  const contract = new ethers.Contract(address, abi, provider);
  if (typeof contract[method] !== 'function') throw new Error(`Method not found: ${method}`);
  return await contract[method](...args);
}

async function writeContract(address, abi, method, args = [], txOptions = {}) {
  const contract = getContract(address, abi);
  if (typeof contract[method] !== 'function') throw new Error(`Method not found: ${method}`);
  const tx = await contract[method](...args, {
    value: txOptions.value ? ethers.parseEther(String(txOptions.value)) : undefined,
    gasLimit: txOptions.gasLimit,
    maxFeePerGas: txOptions.maxFeePerGas,
    maxPriorityFeePerGas: txOptions.maxPriorityFeePerGas,
    nonce: txOptions.nonce,
    chainId: txOptions.chainId ?? CHAIN_ID
  });
  return await tx.wait();
}

async function estimateGasForEthTransfer(to, amountEth) {
  if (!ethers.isAddress(to)) throw new Error('Invalid recipient address');
  return await provider.estimateGas({
    from: wallet.address,
    to,
    value: ethers.parseEther(String(amountEth))
  });
}

async function estimateGasForContract(address, abi, method, args = [], txOptions = {}) {
  const contract = getContract(address, abi);
  if (typeof contract[method] !== 'function') throw new Error(`Method not found: ${method}`);
  const overrides = {
    value: txOptions.value ? ethers.parseEther(String(txOptions.value)) : undefined
  };
  return await contract[method].estimateGas(...args, overrides);
}

async function signMessage(message) {
  return await wallet.signMessage(message);
}

async function signTypedData(domain, types, value) {
  return await wallet.signTypedData(domain, types, value);
}

async function getNonce(address = wallet.address) {
  return await provider.getTransactionCount(address, 'latest');
}

async function getChainId() {
  const network = await provider.getNetwork();
  return Number(network.chainId);
}

